import torch
from torch.nn import functional as F

class EWCRegularizer:
    """Compute Fisher diagonal and apply EWC penalty."""
    def __init__(self, model, general_dataloader, device, n_batches=50):
        self.params_star = {n: p.clone().detach() for n, p in model.named_parameters()
                            if p.requires_grad}
        self.fisher = self._compute_fisher(model, general_dataloader, device, n_batches)

    def _compute_fisher(self, model, dataloader, device, n_batches):
        fisher = {n: torch.zeros_like(p) for n, p in model.named_parameters()
                  if p.requires_grad}
        model.eval()
        for i, batch in enumerate(dataloader):
            if i >= n_batches:
                break
            batch = {k: v.to(device) for k, v in batch.items()}
            output = model(**batch)
            loss = output.loss
            model.zero_grad()
            loss.backward()
            for n, p in model.named_parameters():
                if p.requires_grad and p.grad is not None:
                    fisher[n] += p.grad.detach() ** 2
        # Normalize
        for n in fisher:
            fisher[n] /= n_batches
        return fisher

    def penalty(self, model):
        """Return EWC regularization loss."""
        loss = 0.0
        for n, p in model.named_parameters():
            if p.requires_grad and n in self.fisher:
                loss += (self.fisher[n] * (p - self.params_star[n]) ** 2).sum()
        return loss

